import React from 'react';
import logo from '../Assets/logo.png';
import powerwashing from '../Assets/powerwashing.gif';

const Body = () => {
  return (
    <div>
        <section className="relative h-[628px] bg-cover bg-center" style={{ backgroundImage: `url(${powerwashing})` }}>
        <div className="absolute inset-0 bg-black opacity-50"></div>
        <div className="relative z-10 flex flex-col items-center justify-center h-full text-center text-white">
            <img src={logo} alt="Logo" className="h-16 mb-4" />
            <h1 className="text-4xl md:text-6xl font-bold">YOUR HOME DETAILING EXPERTS</h1>
            <p className="text-lg md:text-2xl mt-4">Serving the Vancouver area since 2022</p>
            <a href="#quote" className="mt-8 px-8 py-3 bg-blue-500 text-white font-bold uppercase rounded hover:bg-blue-700 transition">
            Get A Free Quote
            </a>
        </div>
        </section>
        <section className="p-8 bg-white text-center">
        <h2 className="text-3xl md:text-4xl font-bold text-blue-500 mb-4">"A TEAM OF YOUNG PROFESSIONAL CLEANERS"</h2>
        <p className="text-lg md:text-xl text-gray-700">
          We are a premier home detailing company, specializing in the cleaning and detailing of exterior windows, siding, and gutters. Locally based in Vancouver, we are a team of young professionals looking to service and satisfy customers all over the lower mainland.
        </p>
      </section>
    </div>
  );
};

export default Body;
